import OpenAI from 'openai';
import { VexClient } from 'vex-sdk';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });

export async function POST(request: Request) {
  const event = await request.json();
  if (event.event === 'thread.run.completed') {
    const run = await openai.beta.threads.runs.retrieve(
      event.data.object.thread_id,
      event.data.object.id
    );
    const messages = await openai.beta.threads.messages.list(run.thread_id);

    const result = await vex.verify({
      framework: 'openai-assistants',
      output: messages.data[0].content[0].text.value,
      rules: ['legal_citation_verification', 'pii_redaction', 'ethics_compliance']
    });

    if (!result.passed) {
      await openai.beta.threads.runs.submitToolOutputs(run.thread_id, run.id, [{
        tool_call_id: 'vex-compliance',
        output: JSON.stringify(result.issues)
      }]);
    }
  }
  return new Response('OK');
}
